#!/usr/bin/env perl
use strict;
use warnings;
use File::Path qw(make_path);
use File::Basename;
use Cwd qw(getcwd);

my $MINIGIT_DIR = '.minigit';

sub minihash {
    my ($data) = @_;
    my $h = 1469598103934665603;
    # Use Math::BigInt-like manual 64-bit arithmetic via 'use integer' won't work
    # for unsigned 64-bit. We need to handle mod 2^64 manually.
    # Perl on 64-bit systems with 'use integer' uses signed 64-bit.
    # We'll use no integer and do modular arithmetic with floats won't work either.
    # Best approach: use pack/unpack for unsigned 64-bit math.

    my @bytes = unpack('C*', $data);
    for my $b (@bytes) {
        $h ^= $b;
        # Multiply mod 2^64 using pack/unpack trick
        # Split into high and low 32 bits
        my $lo = $h & 0xFFFFFFFF;
        my $hi = ($h >> 32) & 0xFFFFFFFF;
        my $prime = 1099511628211;
        my $prime_lo = $prime & 0xFFFFFFFF;
        my $prime_hi = ($prime >> 32) & 0xFFFFFFFF;

        # Multiply: result = h * prime mod 2^64
        # Using the fact that on 64-bit perl, integers can handle this
        # Let's just use the native integer math with masking
        use integer;
        $h = $h * 1099511628211;
        no integer;
        # Mask to 64-bit unsigned
        $h = $h & 0xFFFFFFFFFFFFFFFF if $h < 0;
        # Actually on 64-bit Perl with 'use integer', multiplication wraps at 2^63
        # Let's try a different approach
    }
    return sprintf('%016x', $h);
}

# Better approach: use the fact that Perl 64-bit can handle this with careful masking
sub minihash2 {
    my ($data) = @_;
    my @bytes = unpack('C*', $data);

    # Use vec or manual bigint approach
    # Actually, let's just compute using strings and BigInt-like approach
    # Or better: use the native 64-bit with proper unsigned handling

    my $h_hi = 0x14650FB0; # upper 32 bits of 1469598103934665603
    my $h_lo = 0x739D0383; # lower 32 bits

    # 1469598103934665603 = 0x14650FB0739D0383
    # 1099511628211       = 0x00000100000001B3

    my $p_hi = 0x00000100;
    my $p_lo = 0x000001B3;

    for my $b (@bytes) {
        # XOR with byte (only affects low part)
        $h_lo ^= $b;

        # Multiply (h_hi:h_lo) * (p_hi:p_lo) mod 2^64
        # result_lo = (h_lo * p_lo) mod 2^32, carry
        # result_hi = (h_hi * p_lo + h_lo * p_hi + carry) mod 2^32

        my $ll = $h_lo * $p_lo;
        my $r_lo = $ll & 0xFFFFFFFF;
        my $carry = int($ll / 4294967296); # $ll >> 32 but safe for large numbers

        my $r_hi = ($h_hi * $p_lo + $h_lo * $p_hi + $carry) & 0xFFFFFFFF;

        $h_hi = $r_hi;
        $h_lo = $r_lo;
    }

    return sprintf('%08x%08x', $h_hi, $h_lo);
}

sub read_file {
    my ($path) = @_;
    open my $fh, '<:raw', $path or return undef;
    local $/;
    my $content = <$fh>;
    close $fh;
    return $content;
}

sub write_file {
    my ($path, $content) = @_;
    open my $fh, '>:raw', $path or die "Cannot write $path: $!\n";
    print $fh $content;
    close $fh;
}

sub cmd_init {
    if (-d $MINIGIT_DIR) {
        print "Repository already initialized\n";
        return;
    }
    make_path("$MINIGIT_DIR/objects");
    make_path("$MINIGIT_DIR/commits");
    write_file("$MINIGIT_DIR/index", "");
    write_file("$MINIGIT_DIR/HEAD", "");
}

sub cmd_add {
    my ($file) = @_;
    unless (defined $file && -e $file) {
        print "File not found\n";
        exit 1;
    }

    my $content = read_file($file);
    my $hash = minihash2($content);

    write_file("$MINIGIT_DIR/objects/$hash", $content);

    # Read current index
    my $index_content = read_file("$MINIGIT_DIR/index") // "";
    my @entries = grep { $_ ne '' } split(/\n/, $index_content);

    unless (grep { $_ eq $file } @entries) {
        push @entries, $file;
        write_file("$MINIGIT_DIR/index", join("\n", @entries) . (@entries ? "\n" : ""));
    }
}

sub cmd_commit {
    my ($message) = @_;

    my $index_content = read_file("$MINIGIT_DIR/index") // "";
    my @entries = grep { $_ ne '' } split(/\n/, $index_content);

    if (!@entries) {
        print "Nothing to commit\n";
        exit 1;
    }

    my $head = read_file("$MINIGIT_DIR/HEAD") // "";
    chomp $head;
    my $parent = $head eq '' ? 'NONE' : $head;

    my $timestamp = time();

    # Build file list sorted
    my @sorted = sort @entries;
    my @file_lines;
    for my $f (@sorted) {
        my $content = read_file($f);
        my $hash = minihash2($content);
        push @file_lines, "$f $hash";
    }

    my $commit_content = "parent: $parent\n";
    $commit_content .= "timestamp: $timestamp\n";
    $commit_content .= "message: $message\n";
    $commit_content .= "files:\n";
    $commit_content .= join("\n", @file_lines) . "\n";

    my $commit_hash = minihash2($commit_content);

    write_file("$MINIGIT_DIR/commits/$commit_hash", $commit_content);
    write_file("$MINIGIT_DIR/HEAD", $commit_hash);
    write_file("$MINIGIT_DIR/index", "");

    print "Committed $commit_hash\n";
}

sub cmd_log {
    my $head = read_file("$MINIGIT_DIR/HEAD") // "";
    chomp $head;

    if ($head eq '') {
        print "No commits\n";
        return;
    }

    my $current = $head;
    my $first = 1;
    while ($current ne 'NONE' && $current ne '') {
        my $commit_content = read_file("$MINIGIT_DIR/commits/$current");
        unless (defined $commit_content) {
            last;
        }

        print "\n" unless $first;
        $first = 0;

        my ($parent, $timestamp, $message);
        for my $line (split(/\n/, $commit_content)) {
            if ($line =~ /^parent: (.+)$/) {
                $parent = $1;
            } elsif ($line =~ /^timestamp: (.+)$/) {
                $timestamp = $1;
            } elsif ($line =~ /^message: (.+)$/) {
                $message = $1;
            }
        }

        print "commit $current\n";
        print "Date: $timestamp\n";
        print "Message: $message\n";

        $current = $parent // 'NONE';
    }
}

# Main
my $cmd = shift @ARGV;

unless (defined $cmd) {
    print "Usage: minigit <command>\n";
    exit 1;
}

if ($cmd eq 'init') {
    cmd_init();
} elsif ($cmd eq 'add') {
    cmd_add($ARGV[0]);
} elsif ($cmd eq 'commit') {
    # Parse -m "message"
    my $message;
    for (my $i = 0; $i < scalar @ARGV; $i++) {
        if ($ARGV[$i] eq '-m' && $i + 1 < scalar @ARGV) {
            $message = $ARGV[$i + 1];
            last;
        }
    }
    unless (defined $message) {
        print "Usage: minigit commit -m \"message\"\n";
        exit 1;
    }
    cmd_commit($message);
} elsif ($cmd eq 'log') {
    cmd_log();
} else {
    print "Unknown command: $cmd\n";
    exit 1;
}

